public class Solution {
    public int reverseBits(int n) {
        n = (n >> 16) | (n << 16);
        n = ((n & 0x00FF00FF) << 8) | ((n & 0xFF00FF00) >> 8);
        n = ((n & 0x0000FFFF) << 4) | ((n & 0xFFFF0000) >> 4);
        n = ((n & 0x000000FF) << 2) | ((n & 0xFFFFFF00) >> 2);
        n = ((n & 0x0000000F) << 1) | ((n & 0xFFFFFFF0) >> 1);
        return n;
    }
}
